import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def travel_time(distance, speed):
        return distance / speed

    min_score = float('inf')
    best_node = None

    for i, customer in enumerate(unvisited_customers):
        distance = calculate_distance(cur_truck_pos, customer)
        estimated_arrival_time = current_time + travel_time(distance, truck_speed)
        start_window, end_window = time_windows[i]

        # Calculate wait penalty and urgency factor
        if estimated_arrival_time < start_window:
            wait_time = start_window - estimated_arrival_time
            urgency = (end_window - start_window)
            score = wait_time / urgency # Encourage waits that are shorter relative to the window length
        elif estimated_arrival_time > end_window:
            penalty = (estimated_arrival_time - end_window) ** 2
            score = penalty # Significantly disincentivizes lateness
        else:
            score = 0  # Prime situation,No penalty

        # Adjust for customer proximity and remaining window time
        closeness_factor = 1 / (distance + 1)
        remaining_window_time = max(0, end_window - estimated_arrival_time)
        score += (1 - closeness_factor) * remaining_window_time

        if score < min_score:
            min_score = score
            best_node = i

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, 
                     unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(from_pos, to_pos):
        return np.linalg.norm(from_pos - to_pos) / truck_speed

    def calculate_penalty(arrival_time, time_window):
        start, end = time_window
        if arrival_time < start:
            return (start - arrival_time)  # wait time penalty
        elif arrival_time > end:
            return (arrival_time - end) * 10  # missed window penalty
        return 0

    def future_proximity_penalty(customer_index):
        # Sum of distances from the chosen customer to all other unvisited customers
        future_cost = 0
        chosen_pos = unvisited_customers[customer_index]
        for j, pos in enumerate(unvisited_customers):
            if j != customer_index:
                future_cost += np.linalg.norm(chosen_pos - pos)
        return future_cost / len(unvisited_customers)

    min_cost = float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        t_time = travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + t_time
        penalty = calculate_penalty(arrival_time, time_windows[i])

        proximity_penalty = future_proximity_penalty(i)

        # total_cost considers travel, penalty, and future proximity costs
        total_cost = t_time + penalty + 0.1 * proximity_penalty

        if total_cost < min_cost:
            min_cost = total_cost
            best_node = i

    return best_node
